/**
 * Supplemental tests for desktop notification hook: spawn behavior + terminal mapping.
 *
 * Covers the spawn-based delivery introduced in v2.0.0:
 *  - detached: true, stdio: 'ignore', child.unref()
 *  - Terminal app name mapping (TERM_PROGRAM → macOS app name)
 *
 * Core behavior tests live in desktop.test.ts.
 * CC 2.1.7 Compliance: all paths return { continue: true, suppressOutput: true }
 */

import { describe, test, expect, vi, beforeEach, afterEach } from 'vitest';
import type { HookInput } from '../../types.js';

// =============================================================================
// Hoisted mocks (vi.hoisted runs before vi.mock factory)
// =============================================================================

const { mockUnref, mockSpawn } = vi.hoisted(() => {
  const mockUnref = vi.fn();
  const mockSpawn = vi.fn(() => ({ unref: mockUnref }));
  return { mockUnref, mockSpawn };
});

// =============================================================================
// Mocks
// =============================================================================

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
    getProjectDir: vi.fn(() => '/test/projects/orchestkit'),
    getCachedBranch: vi.fn(() => 'main'),
  };
});

vi.mock('node:child_process', () => ({
  execFileSync: vi.fn(() => ''),
  spawn: mockSpawn,
}));

vi.mock('node:path', async () => {
  const actual = await vi.importActual<typeof import('node:path')>('node:path');
  return { ...actual, basename: actual.basename };
});

// =============================================================================
// Imports (after mocks)
// =============================================================================

import { desktopNotification, _resetCommandCacheForTesting } from '../../notification/desktop.js';
import { execFileSync } from 'node:child_process';
import { createTestContext } from '../fixtures/test-context.js';

// =============================================================================
// Test Utilities
// =============================================================================

function createNotificationInput(notificationType: string): HookInput {
  return {
    hook_event: 'Notification',
    tool_name: 'Notification',
    session_id: 'test-session-123',
    tool_input: { notification_type: notificationType, message: 'Test message' },
    message: 'Test message',
    notification_type: notificationType,
  };
}

// =============================================================================
// Tests
// =============================================================================

let testCtx: ReturnType<typeof createTestContext>;
describe('notification/desktop — spawn behavior', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
    _resetCommandCacheForTesting();
    // execFileSync used for `which` availability checks
    vi.mocked(execFileSync).mockImplementation((cmd: unknown, args: unknown) => {
      const argStr = (args as string[])?.join(' ') ?? '';
      if (cmd === 'which' && argStr.includes('osascript')) return Buffer.from('/usr/bin/osascript');
      if (cmd === 'which' && argStr.includes('notify-send')) throw new Error('not found');
      return Buffer.from('');
    });
    mockSpawn.mockReturnValue({ unref: mockUnref });
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  // ---------------------------------------------------------------------------
  // Spawn delivery options
  // ---------------------------------------------------------------------------

  describe('spawn-based notification delivery', () => {
    test('spawns osascript with detached: true', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'osascript');
      expect(calls).toHaveLength(1);
      expect(calls[0][2]).toMatchObject({ detached: true });
    });

    test('uses stdio: ignore when spawning osascript', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'osascript');
      expect(calls).toHaveLength(1);
      expect(calls[0][2]).toMatchObject({ stdio: 'ignore' });
    });

    test('calls unref on the spawned osascript child process', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      expect(mockUnref).toHaveBeenCalled();
    });

    test('passes -e flag followed by full AppleScript to osascript', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'osascript');
      expect(calls).toHaveLength(1);
      const args: string[] = calls[0][1] as string[];
      expect(args[0]).toBe('-e');
      expect(typeof args[1]).toBe('string');
      expect(args[1]).toContain('display notification');
    });

    test('returns silentSuccess when spawn throws', async () => {
      mockSpawn.mockImplementationOnce(() => { throw new Error('spawn ENOENT'); });
      const result = await desktopNotification(createNotificationInput('permission_prompt'));
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('spawns notify-send with detached: true on Linux', async () => {
      vi.mocked(execFileSync).mockImplementation((cmd: unknown, args: unknown) => {
        const argStr = (args as string[])?.join(' ') ?? '';
        if (cmd === 'which' && argStr.includes('osascript')) throw new Error('not found');
        if (cmd === 'which' && argStr.includes('notify-send')) return Buffer.from('/usr/bin/notify-send');
        return Buffer.from('');
      });
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'notify-send');
      expect(calls).toHaveLength(1);
      expect(calls[0][2]).toMatchObject({ detached: true, stdio: 'ignore' });
    });

    test('calls unref on spawned notify-send child process', async () => {
      vi.mocked(execFileSync).mockImplementation((cmd: unknown, args: unknown) => {
        const argStr = (args as string[])?.join(' ') ?? '';
        if (cmd === 'which' && argStr.includes('osascript')) throw new Error('not found');
        if (cmd === 'which' && argStr.includes('notify-send')) return Buffer.from('/usr/bin/notify-send');
        return Buffer.from('');
      });
      await desktopNotification(createNotificationInput('permission_prompt'));
      expect(mockUnref).toHaveBeenCalled();
    });

    test('passes title and message as separate argv items to notify-send', async () => {
      vi.mocked(execFileSync).mockImplementation((cmd: unknown, args: unknown) => {
        const argStr = (args as string[])?.join(' ') ?? '';
        if (cmd === 'which' && argStr.includes('osascript')) throw new Error('not found');
        if (cmd === 'which' && argStr.includes('notify-send')) return Buffer.from('/usr/bin/notify-send');
        return Buffer.from('');
      });
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'notify-send');
      expect(calls).toHaveLength(1);
      // spawn('notify-send', ['--', title, fullMessage], options)
      const args: string[] = calls[0][1] as string[];
      expect(args[0]).toBe('--');
      expect(typeof args[1]).toBe('string'); // title
      expect(typeof args[2]).toBe('string'); // message body
    });
  });

  // ---------------------------------------------------------------------------
  // No focus stealing
  // ---------------------------------------------------------------------------

  describe('no focus stealing', () => {
    test('osascript script does not contain activate clause', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'osascript');
      expect(calls).toHaveLength(1);
      const script: string = (calls[0] as any[])[1][1] as string;
      expect(script).not.toContain('activate');
      expect(script).not.toContain('tell application');
    });

    test('osascript script only contains display notification', async () => {
      await desktopNotification(createNotificationInput('permission_prompt'));
      const calls = (mockSpawn.mock.calls as any[][]).filter((c: any[]) => c[0] === 'osascript');
      const script: string = (calls[0] as any[])[1][1] as string;
      expect(script).toContain('display notification');
      expect(script).toContain('with title');
      expect(script).toContain('subtitle');
    });
  });
});
